const sqlite3 = require('sqlite3').verbose();
const path = require('path');

const dbPath = path.resolve(__dirname, '../database.sqlite');

const db = new sqlite3.Database(dbPath, (err) => {
  if (err) {
    console.error('Error opening database', err);
  } else {
    console.log('Connected to SQLite database.');
    initializeDatabase();
  }
});

function initializeDatabase() {
  db.serialize(() => {
    db.run(`CREATE TABLE IF NOT EXISTS products (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      barcode TEXT UNIQUE NOT NULL,
      category TEXT,
      selling_price REAL NOT NULL,
      cost_price REAL NOT NULL,
      stock INTEGER DEFAULT 0,
      min_stock INTEGER DEFAULT 5,
      image_url TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )`);

    db.run(`CREATE TABLE IF NOT EXISTS transactions (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      total REAL NOT NULL,
      tax REAL DEFAULT 0,
      discount REAL DEFAULT 0,
      payment_method TEXT NOT NULL,
      cash_given REAL,
      change_due REAL,
      cashier_name TEXT DEFAULT 'Cashier',
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    )`);

    db.run(`CREATE TABLE IF NOT EXISTS transaction_items (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      transaction_id INTEGER,
      product_id INTEGER,
      product_name TEXT,
      quantity INTEGER NOT NULL,
      price REAL NOT NULL,
      FOREIGN KEY (transaction_id) REFERENCES transactions(id),
      FOREIGN KEY (product_id) REFERENCES products(id)
    )`);

    db.get("SELECT COUNT(*) as count FROM products", (err, row) => {
      if (row.count === 0) {
        const sampleProducts = [
          ['Milk', '123456789', 'Dairy', 2.99, 1.99, 50, 10],
          ['Bread', '987654321', 'Bakery', 1.99, 1.20, 30, 5],
          ['Eggs', '456789123', 'Dairy', 3.49, 2.50, 20, 5]
        ];
        const stmt = db.prepare("INSERT INTO products (name, barcode, category, selling_price, cost_price, stock, min_stock) VALUES (?,?,?,?,?,?,?)");
        sampleProducts.forEach(p => stmt.run(p[0], p[1], p[2], p[3], p[4], p[5], p[6]));
        stmt.finalize();
        console.log('Sample products inserted');
      }
    });
  });
}

module.exports = db;
